const EVENTS=['50 Free SCY','50 Free LCM','100 Free SCY','100 Free LCM','200 Free SCY','200 Free LCM','500 Free SCY','400 Free LCM','1000 Free SCY','800 Free LCM','1650 Free SCY','1500 Free LCM','50 Back SCY','50 Back LCM','100 Back SCY','100 Back LCM','200 Back SCY','200 Back LCM','50 Breast SCY','50 Breast LCM','100 Breast SCY','100 Breast LCM','200 Breast SCY','200 Breast LCM','50 Fly SCY','50 Fly LCM','100 Fly SCY','100 Fly LCM','200 Fly SCY','200 Fly LCM','100 IM SCY','200 IM SCY','200 IM LCM','400 IM SCY','400 IM LCM'];
const STROKES=['Free','Back','Breast','Fly','IM'];
const WEB_BETA_STORAGE_KEY='swimWebBeta_v1';
function gStroke(e){for(const s of STROKES)if(e.includes(s))return s;return 'Other';}

function t2s(t){
  if(t===null||t===undefined)return null;
  const s=String(t).trim();
  if(!s||s==='null'||s==='None')return null;
  const f=parseFloat(s);
  if(!isNaN(f)&&!s.includes(':'))return f;
  const m=s.match(/^(\d+):(\d+(?:\.\d+)?)$/);
  if(m)return parseInt(m[1])*60+parseFloat(m[2]);
  return null;
}

let S={athletes:[],standards:[],teamName:'Demo Swim Club',teamLogo:null,theme:'dark',meets:[]};
let curPage='roster',gFilt='all',chartG='female',stdVG='female';
let editAthId=null,editTimesId=null,teStroke='Free',lbG='all',evST='All';

function dc(x){return JSON.parse(JSON.stringify(x));}

function createDefaultState(){
  return {
    athletes:dc(DEFAULT_ATHLETES),
    standards:dc(DEFAULT_STANDARDS),
    teamName:'Demo Swim Club',
    teamLogo:null,
    theme:'dark',
    meets:dc(DEFAULT_MEETS)
  };
}

function snapshotState(){
  return {
    athletes:S.athletes,
    standards:S.standards,
    teamName:S.teamName,
    teamLogo:S.teamLogo,
    theme:S.theme || 'dark',
    meets:S.meets || []
  };
}

function loadState(){
  try{
    const fallback=createDefaultState();
    let p=null;
    if(window.WebBetaAuth&&window.WebBetaAuth.isUnlocked&&window.WebBetaAuth.isUnlocked()){
      p=window.__WEB_BETA_UNLOCKED_STATE__||null;
    }else{
      const d=localStorage.getItem(WEB_BETA_STORAGE_KEY);
      if(d)p=JSON.parse(d);
    }
    S.athletes=p?.athletes||fallback.athletes;
    S.standards=p?.standards||fallback.standards;
    S.teamName=p?.teamName||fallback.teamName;
    S.teamLogo=p?.teamLogo||fallback.teamLogo;
    S.theme=p?.theme||fallback.theme;
    S.meets=p?.meets||fallback.meets;
  }catch(e){
    const fallback=createDefaultState();
    S.athletes=fallback.athletes;
    S.standards=fallback.standards;
    S.teamName=fallback.teamName;
    S.teamLogo=fallback.teamLogo;
    S.theme=fallback.theme;
    S.meets=fallback.meets;
  }
  // Apply saved theme
  if(S.theme==='light'){
    document.body.classList.add('light-mode');
  } else {
    document.body.classList.remove('light-mode');
  }
}
function save(){
  const snap=snapshotState();
  try{
    if(window.WebBetaAuth&&window.WebBetaAuth.isUnlocked&&window.WebBetaAuth.isUnlocked()){
      window.WebBetaAuth.queueWrite(snap);
    }else{
      localStorage.setItem(WEB_BETA_STORAGE_KEY,JSON.stringify(snap));
    }
  }catch(e){}
}

// ── CUT LOGIC ────────────────────────────────────────────────
function getBestCut(a,ev){
  const t=a.times[ev];if(!t)return null;
  const ts=t2s(t);if(ts===null)return null;
  const tk=a.gender==='female'?'timesF':'timesM';
  let best=null;
  const sorted=[...S.standards].sort((a,b)=>a.priority-b.priority);
  for(const std of sorted){
    const sv=std[tk][ev];if(!sv)continue;
    const ss=t2s(sv);if(ss===null)continue;
    if(ts<=ss)best=std;
  }
  return best;
}

function getStats(a){
  const cuts={},byStd={};
  S.standards.forEach(s=>byStd[s.id]=0);
  for(const ev of EVENTS){
    // Count cuts per standard independently — no subsumption
    const tk=a.gender==='female'?'timesF':'timesM';
    const ats=t2s(a.times[ev]);
    if(ats===null) continue;
    S.standards.forEach(s=>{
      const sv=s[tk][ev]; if(!sv) return;
      const ss=t2s(sv); if(ss===null) return;
      if(ats<=ss) byStd[s.id]++;
    });
    // cuts{} still tracks the BEST (highest priority) cut per event for coloring
    const c=getBestCut(a,ev);
    if(c) cuts[ev]=c;
  }
  // total = sum of every cut achieved across every standard
  const total=Object.values(byStd).reduce((s,n)=>s+n,0);
  return{cuts,byStd,total};
}

function badges(stats,large){
  return S.standards.map(std=>{
    const n=stats.byStd[std.id]||0,has=n>0;
    const bgN=has?std.color:'rgba(255,255,255,0.06)';
    const bgL=has?std.color+'22':'rgba(255,255,255,0.03)';
    const cN=has?'#fff':'rgba(255,255,255,0.2)';
    const cL=has?std.color:'rgba(255,255,255,0.18)';
    const bdr=has?std.color+'55':'rgba(255,255,255,0.06)';
    const fN=large?'18px':'14px',pN=large?'5px 8px 5px 10px':'4px 7px 4px 8px';
    const fL=large?'11px':'10px',pL=large?'5px 10px 5px 6px':'4px 8px 4px 5px';
    return `<span class="sb" style="border-color:${bdr}"><span class="sbc" style="background:${bgN};color:${cN};font-size:${fN};padding:${pN}">${n}</span><span class="sbn" style="background:${bgL};color:${cL};font-size:${fL};padding:${pL}">${std.name}</span></span>`;
  }).join('');
}

// ── ROSTER ───────────────────────────────────────────────────
function renderRoster(){
  const q=document.getElementById('srch').value.toLowerCase();
  const list=document.getElementById('rosterList');
  const aths=S.athletes.filter(a=>{
    if(gFilt==='male'&&a.gender!=='male')return false;
    if(gFilt==='female'&&a.gender!=='female')return false;
    return !q||a.name.toLowerCase().includes(q);
  });
  if(!aths.length){list.innerHTML='<div class="nd"><div class="ndi">🏊</div>No athletes found</div>';return;}
  list.innerHTML=aths.map(a=>{
    const st=getStats(a);
    const ini=a.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
    const allCuts=Object.entries(st.cuts);
    const pillsHtml=allCuts.map(([ev,std])=>
      `<span class="cut-pill" style="background:${std.color}22;border:1px solid ${std.color}55;color:${std.color}" data-std="${std.id}">${ev}</span>`
    ).join('');
    const toggleBtns=S.standards.map(std=>{
      const n=st.byStd[std.id]||0;
      if(!n)return '';
      return `<button class="pills-toggle-btn" onclick="event.stopPropagation();togglePills(this,'${std.id}')" style="border-color:${std.color}44;color:${std.color}">${n} ${std.name}</button>`;
    }).filter(Boolean).join('');
    return `<div class="ac ${a.gender}" onclick="showProfile('${a.id}')">
      <div class="ahdr">
        <div class="av ${a.gender}">${ini}</div>
        <div style="flex:1;min-width:0;"><div class="aname">${a.name}</div><div class="ameta">${a.gender==='female'?'♀':'♂'}${a.age?' · '+a.age:''} · ${Object.keys(a.times).length} events · ${st.total} cuts</div></div>
        <button class="btn bsm bs" onclick="event.stopPropagation();openEditAth('${a.id}')" style="flex-shrink:0">✏️</button>
      </div>
      <div class="brow">${badges(st,false)}</div>
      ${allCuts.length?`
      <div style="display:flex;align-items:center;gap:5px;flex-wrap:wrap;margin-top:7px;">
        <button class="pills-toggle-btn" onclick="event.stopPropagation();togglePills(this,'all')">🏅 ${allCuts.length} cuts</button>
        ${toggleBtns}
      </div>
      <div class="cut-pills-row" data-pills>${pillsHtml}</div>`:''}
    </div>`;
  }).join('');
}

function togglePills(btn,filterId){
  const card=btn.closest('.ac');
  const pillsRow=card.querySelector('[data-pills]');
  const allBtns=card.querySelectorAll('.pills-toggle-btn');
  const pills=pillsRow.querySelectorAll('.cut-pill');
  const isActive=btn.classList.contains('active');
  allBtns.forEach(b=>b.classList.remove('active'));
  pillsRow.classList.remove('open');
  if(isActive)return;
  btn.classList.add('active');
  pillsRow.classList.add('open');
  pills.forEach(pill=>{
    if(filterId==='all'){pill.style.display='';}
    else{
      const sel=S.standards.find(s=>s.id===filterId);
      const pStd=S.standards.find(s=>s.id===pill.dataset.std);
      pill.style.display=(sel&&pStd&&pStd.priority<=sel.priority)?'':'none';
    }
  });
}

// ── PROFILE ──────────────────────────────────────────────────
function showProfile(id){
  const a=S.athletes.find(x=>x.id===id);if(!a)return;
  // Use roadmap-aware builder if available, else fall back
  if(typeof buildRoadmapProfileContent==='function'){
    initProfileRoadmap(id);
    document.getElementById('profileContent').innerHTML=buildRoadmapProfileContent(a);
    document.getElementById('profileContent').dataset.athleteId=id;
  } else {
    const st=getStats(a);
    const ini=a.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
    let timesHtml='';
    for(const stroke of STROKES){
      const evs=EVENTS.filter(e=>gStroke(e)===stroke&&a.times[e]);if(!evs.length)continue;
      timesHtml+=`<div style="margin-bottom:13px;"><div class="ctitle">${stroke}</div><div class="tgrid">${evs.map(ev=>{
        const t=a.times[ev];const c=getBestCut(a,ev);
        return `<div class="tcell" style="background:${c?c.color+'22':'var(--sur2)'};border-color:${c?c.color:'var(--bdr)'}"><div class="tev">${ev}</div><div class="tval">${t}</div>${c?`<div class="tstd" style="color:${c.color}">● ${c.name}</div>`:''}</div>`;
      }).join('')}</div></div>`;
    }
    document.getElementById('profileContent').innerHTML=`
      <div class="phdr">
        <div class="pav ${a.gender}">${ini}</div>
        <div style="flex:1;min-width:0;"><div class="pname">${a.name}</div><div style="font-size:12px;color:var(--muted);margin-bottom:8px;">${a.gender==='female'?'♀ Female':'♂ Male'}${a.age?' · '+a.age:''} · ${Object.keys(a.times).length} events</div><div class="brow">${badges(st,true)}</div></div>
      </div>
      <div style="display:flex;gap:7px;flex-wrap:wrap;margin-bottom:13px;">
        <button class="btn bsm bp" onclick="openEditTimes('${id}')">Edit Times</button>
        <button class="btn bsm bs" onclick="openEditAth('${id}')">Edit Info</button>
        <button class="btn bsm bd" onclick="delAth('${id}')">Delete</button>
      </div>
      ${timesHtml||'<div style="color:var(--muted);font-size:13px;padding:20px 0;text-align:center;">No times recorded yet</div>'}`;
  }
  showPage('profile');
}

// ── CHART ────────────────────────────────────────────────────
function renderChart(){
  const aths=S.athletes.filter(a=>a.gender===chartG);
  let html='<thead><tr><th>Athlete</th>';
  EVENTS.forEach(ev=>html+=`<th>${ev}</th>`);
  html+='</tr></thead><tbody>';
  aths.forEach(a=>{
    html+=`<tr><td onclick="showProfile('${a.id}')" style="cursor:pointer;color:var(--acc)">${a.name}</td>`;
    EVENTS.forEach(ev=>{
      const t=a.times[ev];const c=t?getBestCut(a,ev):null;
      html+=`<td style="${c?`background:${c.color}33;color:${c.color};font-weight:700;`:''}">${t||'<span style="color:rgba(255,255,255,.12);font-size:10px;">—</span>'}</td>`;
    });
    html+='</tr>';
  });
  document.getElementById('rctTbl').innerHTML=html+'</tbody>';
  document.getElementById('cgBtn').textContent=chartG==='female'?'Women':'Men';
}

// ── OVERVIEW ─────────────────────────────────────────────────
function renderOverview(){
  const tot=S.athletes.reduce((s,a)=>s+getStats(a).total,0);
  document.getElementById('ovStats').innerHTML=`
    <div class="scard"><div class="snum">${S.athletes.length}</div><div class="slbl">Athletes</div></div>
    <div class="scard"><div class="snum">${tot}</div><div class="slbl">Total Cuts</div></div>
    <div class="scard"><div class="snum">${S.athletes.filter(a=>a.gender==='male').length}</div><div class="slbl">Men</div></div>
    <div class="scard"><div class="snum">${S.athletes.filter(a=>a.gender==='female').length}</div><div class="slbl">Women</div></div>`;
  const sel=document.getElementById('lbStdSel');
  sel.innerHTML='<option value="all">All Standards</option>'+S.standards.map(s=>`<option value="${s.id}">${s.name}</option>`).join('');
  renderLB();renderEvChart();renderStrokeChart();renderStdBarChart();
  if(typeof renderBubbleWidget==='function'){renderBubbleThresholdNote();renderBubbleWidget(bubbleGender);}
}

let bubbleGender = 'all';
function setBubbleG(g) {
  bubbleGender = g;
  ['All','M','F'].forEach(x => document.getElementById('bbg'+x).className='gbtn');
  document.getElementById('bbg'+{all:'All',male:'M',female:'F'}[g]).className='gbtn '+ {all:'aa',male:'am',female:'af'}[g];
  renderBubbleThresholdNote();
  renderBubbleWidget(g);
}
function renderBubbleThresholdNote() {
  const el = document.getElementById('bubbleThresholdNote');
  if (el) el.textContent = 'Thresholds: 50s < 0.8s · 100s < 1.5s · 200s < 3.0s · 500s < 5.0s · 1000s < 8.0s · 1650s < 12.0s';
}

function renderLB(){
  const sid=document.getElementById('lbStdSel').value;
  let aths=S.athletes;if(lbG!=='all')aths=aths.filter(a=>a.gender===lbG);
  const ranked=aths.map(a=>{const st=getStats(a);return{...a,cnt:sid==='all'?st.total:(st.byStd[sid]||0)};}).filter(a=>a.cnt>0).sort((a,b)=>b.cnt-a.cnt);
  document.getElementById('leaderboard').innerHTML=ranked.slice(0,15).map((a,i)=>{
    const ini=a.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase();
    return `<div class="lbr"><div class="lbrk ${i<3?'t3':''}">${i===0?'🥇':i===1?'🥈':i===2?'🥉':i+1}</div><div class="av ${a.gender}" style="width:28px;height:28px;font-size:11px;">${ini}</div><div class="lbn">${a.name}</div><div class="lbc">${a.cnt} cuts</div></div>`;
  }).join('')||'<div style="color:var(--muted);padding:12px;text-align:center;font-size:13px;">No data</div>';
}

function renderEvChart(){
  const tabs=document.getElementById('evStrokeTabs');
  if(!tabs.children.length){
    ['All',...STROKES].forEach(s=>{
      const b=document.createElement('button');b.className='stab'+(s===evST?' active':'');b.textContent=s;
      b.onclick=()=>{evST=s;tabs.querySelectorAll('.stab').forEach(x=>x.classList.remove('active'));b.classList.add('active');buildEvChart();};
      tabs.appendChild(b);
    });
  }
  buildEvChart();
}
function buildEvChart(){
  const evs=EVENTS.filter(e=>evST==='All'||gStroke(e)===evST);
  const data=evs.map(ev=>({ev,n:S.athletes.filter(a=>getBestCut(a,ev)!==null).length})).sort((a,b)=>b.n-a.n);
  const mx=Math.max(...data.map(d=>d.n),1);
  const cols=['#934337','#b05040','#c8705a','#d4987a'];
  document.getElementById('evChart').innerHTML=`<div class="bc">${data.map((d,i)=>`<div class="br"><div class="bl">${d.ev}</div><div class="bt"><div class="bf" style="width:${d.n/mx*100}%;background:${cols[i%4]}">${d.n>0?d.n:''}</div></div><div class="bn">${d.n}</div></div>`).join('')}</div>`;
}
function renderStrokeChart(){
  const data=STROKES.map(s=>{const evs=EVENTS.filter(e=>gStroke(e)===s);const n=S.athletes.reduce((sum,a)=>sum+evs.filter(e=>getBestCut(a,e)!==null).length,0);return{s,n};}).sort((a,b)=>b.n-a.n);
  const mx=Math.max(...data.map(d=>d.n),1);
  document.getElementById('strokeChart').innerHTML=`<div class="bc">${data.map(d=>`<div class="br"><div class="bl">${d.s}</div><div class="bt"><div class="bf" style="width:${d.n/mx*100}%;background:var(--acc2)">${d.n>0?d.n:''}</div></div><div class="bn">${d.n}</div></div>`).join('')}</div>`;
}
function renderStdBarChart(){
  const data=S.standards.map(std=>{const n=S.athletes.reduce((s,a)=>s+(getStats(a).byStd[std.id]||0),0);return{std,n};}).sort((a,b)=>b.n-a.n);
  const mx=Math.max(...data.map(d=>d.n),1);
  document.getElementById('stdBarChart').innerHTML=`<div class="bc">${data.map(d=>`<div class="br"><div class="bl" style="color:${d.std.color}">${d.std.name}</div><div class="bt"><div class="bf" style="width:${d.n/mx*100}%;background:${d.std.color}">${d.n>0?d.n:''}</div></div><div class="bn">${d.n}</div></div>`).join('')}</div>`;
}

// ── STANDARDS TABLE ──────────────────────────────────────────
function renderStdsTable(){
  const tk=stdVG==='female'?'timesF':'timesM';
  let html='<thead><tr><th>Event</th>';
  S.standards.forEach(s=>html+=`<th style="color:${s.color}">${s.name}</th>`);
  html+='</tr></thead><tbody>';
  EVENTS.forEach(ev=>{
    if(!S.standards.some(s=>s[tk][ev]))return;
    html+=`<tr><td>${ev}</td>`;S.standards.forEach(s=>html+=`<td style="color:${s[tk][ev]?s.color:'var(--muted)'}">${s[tk][ev]||'—'}</td>`);html+='</tr>';
  });
  document.getElementById('stdsTbl').innerHTML=html+'</tbody>';
  document.getElementById('svgBtn').textContent=stdVG==='female'?'Women':'Men';
}

// ── SETTINGS ─────────────────────────────────────────────────
function renderSettStds(){
  document.getElementById('settStds').innerHTML=S.standards.map(s=>`<div class="stdsc"><div class="sdot" style="background:${s.color};border:2px solid ${s.color}88"></div><div class="ssi"><div class="ssn" style="color:${s.color}">${s.name}</div><div class="sss">Priority ${s.priority}</div></div><button class="btn bsm bs" onclick="editStd('${s.id}')">✏️</button><button class="btn bsm bd" onclick="delStd('${s.id}')">🗑️</button></div>`).join('')||'<div style="color:var(--muted);font-size:12px;">No standards</div>';
}

// ── MANAGE STANDARDS ─────────────────────────────────────────
function renderStdList(){
  document.getElementById('stdList').innerHTML=S.standards.map(s=>`<div class="stdsc"><div class="sdot" style="background:${s.color}"></div><div class="ssi"><div class="ssn" style="color:${s.color}">${s.name}</div><div class="sss">Priority ${s.priority} · ${Object.keys(s.timesF).length}W / ${Object.keys(s.timesM).length}M</div></div><button class="btn bsm bs" onclick="editStd('${s.id}')">✏️</button><button class="btn bsm bd" onclick="delStd('${s.id}')">🗑️</button></div>`).join('');
  const ab=document.getElementById('addStdBtn');
  ab.innerHTML=S.standards.length<6?'<button class="btn bp bfl" onclick="showAddStdF()">+ Add Standard</button>':`<div style="color:var(--muted);font-size:12px;text-align:center;padding:8px;">Max 6 standards</div>`;
  document.getElementById('addStdForm').style.display='none';
  document.getElementById('editStdForm').style.display='none';
}

function buildSTI(cid,sid,g){
  const c=document.getElementById(cid);if(!c)return;
  const tk=g==='F'?'timesF':'timesM';const std=sid?S.standards.find(s=>s.id===sid):null;
  c.innerHTML=EVENTS.map(ev=>`<div class="stirow"><div class="stiev">${ev}</div><input class="stiin" type="text" data-ev="${ev}" data-g="${g}" value="${std?(std[tk][ev]||''):''}" placeholder="—"></div>`).join('');
}

function showAddStdF(){
  document.getElementById('addStdBtn').style.display='none';
  const f=document.getElementById('addStdForm');f.style.display='block';
  const defColor='2563eb';
  f.innerHTML=`<div class="div"></div>
    <div class="fg"><label class="fl">Name</label><input type="text" class="fi" id="nsN" placeholder="e.g. State Champs"></div>
    <div class="fr">
      <div class="fg"><label class="fl">Color</label>
        <div class="color-picker-wrap">
          <div class="color-swatch" id="nsSwatch" style="background:#${defColor}" onclick="openColorPicker('${defColor}',col=>{document.getElementById('nsHex').value=col.replace('#','');document.getElementById('nsSwatch').style.background=col;})"></div>
          <input type="text" class="fi cs-hex" id="nsHex" value="${defColor}" maxlength="6" placeholder="hex code" oninput="document.getElementById('nsSwatch').style.background='#'+this.value">
        </div>
      </div>
      <div class="fg"><label class="fl">Priority (1=easiest, 6=hardest)</label><input type="number" class="fi" id="nsP" value="${S.standards.length+1}" min="1" max="6"></div>
    </div>
    <div style="font-family:'Inter',sans-serif;font-weight:700;font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--muted);margin-bottom:7px;">Women's Times</div>
    <div class="stisec" id="nsTF"></div><div class="div"></div>
    <div style="font-family:'Inter',sans-serif;font-weight:700;font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--muted);margin-bottom:7px;">Men's Times</div>
    <div class="stisec" id="nsTM"></div>
    <div class="brow2"><button class="btn bp bfl" onclick="saveNewStd()">Add Standard</button><button class="btn bs" onclick="document.getElementById('addStdBtn').style.display='block';document.getElementById('addStdForm').style.display='none'">Cancel</button></div>`;
  buildSTI('nsTF',null,'F');buildSTI('nsTM',null,'M');
}

function saveNewStd(){
  const name=document.getElementById('nsN').value.trim();if(!name)return alert('Enter a name');
  const color='#'+(document.getElementById('nsHex').value.replace('#','')||'2563eb');
  const pri=parseInt(document.getElementById('nsP').value)||S.standards.length+1;
  const tF={},tM={};
  document.querySelectorAll('#nsTF .stiin').forEach(i=>{if(i.value.trim())tF[i.dataset.ev]=i.value.trim();});
  document.querySelectorAll('#nsTM .stiin').forEach(i=>{if(i.value.trim())tM[i.dataset.ev]=i.value.trim();});
  S.standards.push({id:'s'+Date.now(),name,color,priority:pri,timesF:tF,timesM:tM});
  save();renderStdList();renderSettStds();renderStdsTable();renderRoster();
}

function editStd(id){
  const std=S.standards.find(s=>s.id===id);if(!std)return;
  document.getElementById('addStdBtn').style.display='none';
  document.getElementById('addStdForm').style.display='none';
  const ef=document.getElementById('editStdForm');ef.style.display='block';
  const hexVal=std.color.replace('#','');
  ef.innerHTML=`<div class="div"></div>
    <div style="color:${std.color};font-family:'Inter',sans-serif;font-weight:700;font-size:14px;margin-bottom:11px;">Editing: ${std.name}</div>
    <div class="fg"><label class="fl">Name</label><input type="text" class="fi" id="esN" value="${std.name}"></div>
    <div class="fr">
      <div class="fg"><label class="fl">Color</label>
        <div class="color-picker-wrap">
          <div class="color-swatch" id="esSwatch" style="background:${std.color}" onclick="openColorPicker('${hexVal}',col=>{document.getElementById('esHex').value=col.replace('#','');document.getElementById('esSwatch').style.background=col;})"></div>
          <input type="text" class="fi cs-hex" id="esHex" value="${hexVal}" maxlength="6" placeholder="hex code" oninput="document.getElementById('esSwatch').style.background='#'+this.value">
        </div>
      </div>
      <div class="fg"><label class="fl">Priority</label><input type="number" class="fi" id="esP" value="${std.priority}" min="1" max="6"></div>
    </div>
    <div style="font-family:'Inter',sans-serif;font-weight:700;font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--muted);margin-bottom:7px;">Women's Times</div>
    <div class="stisec" id="esTF"></div><div class="div"></div>
    <div style="font-family:'Inter',sans-serif;font-weight:700;font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--muted);margin-bottom:7px;">Men's Times</div>
    <div class="stisec" id="esTM"></div>
    <div class="brow2"><button class="btn bp" onclick="saveEditedStd('${id}')">Save</button><button class="btn bs" onclick="document.getElementById('editStdForm').style.display='none';document.getElementById('addStdBtn').style.display='block'">Cancel</button></div>`;
  buildSTI('esTF',id,'F');buildSTI('esTM',id,'M');
}

function saveEditedStd(id){
  const std=S.standards.find(s=>s.id===id);if(!std)return;
  std.name=document.getElementById('esN').value.trim()||std.name;
  std.color='#'+(document.getElementById('esHex').value.replace('#','')||std.color.replace('#',''));
  std.priority=parseInt(document.getElementById('esP').value)||std.priority;
  const tF={},tM={};
  document.querySelectorAll('#esTF .stiin').forEach(i=>{if(i.value.trim())tF[i.dataset.ev]=i.value.trim();});
  document.querySelectorAll('#esTM .stiin').forEach(i=>{if(i.value.trim())tM[i.dataset.ev]=i.value.trim();});
  std.timesF=tF;std.timesM=tM;
  save();
  document.getElementById('editStdForm').style.display='none';
  document.getElementById('addStdBtn').style.display='block';
  renderStdList();renderSettStds();renderStdsTable();renderRoster();
}

function delStd(id){if(!confirm('Delete this standard?'))return;S.standards=S.standards.filter(s=>s.id!==id);save();renderStdList();renderSettStds();renderStdsTable();renderRoster();}

// ── ATHLETES ─────────────────────────────────────────────────
function openAddAth(){editAthId=null;document.getElementById('athMT').textContent='Add Athlete';document.getElementById('inAN').value='';document.getElementById('inAG').value='female';document.getElementById('inAA').value='';openModal('math');}
function openEditAth(id){const a=S.athletes.find(x=>x.id===id);if(!a)return;editAthId=id;document.getElementById('athMT').textContent='Edit Athlete';document.getElementById('inAN').value=a.name;document.getElementById('inAG').value=a.gender;document.getElementById('inAA').value=a.age||'';openModal('math');}
function saveAthlete(){
  const name=document.getElementById('inAN').value.trim();if(!name)return;
  const gender=document.getElementById('inAG').value;const age=document.getElementById('inAA').value.trim();
  if(editAthId){const a=S.athletes.find(x=>x.id===editAthId);if(a){a.name=name;a.gender=gender;a.age=age;}}
  else S.athletes.push({id:'a'+Date.now(),name,gender,age,times:{}});
  save();closeModal('math');renderRoster();
}
function delAth(id){if(!confirm('Delete this athlete?'))return;S.athletes=S.athletes.filter(a=>a.id!==id);save();showPage('roster');renderRoster();}

function openEditTimes(id){
  editTimesId=id;teStroke='Free';
  const a=S.athletes.find(x=>x.id===id);
  document.getElementById('timesMT').textContent=a.name+' — Times';
  renderTeSTabs();renderTeGrid();openModal('mtimes');
}
function renderTeSTabs(){document.getElementById('teSTabs').innerHTML=STROKES.map(s=>`<button class="stab${s===teStroke?' active':''}" onclick="setTeS('${s}')">${s}</button>`).join('');}
function setTeS(s){teStroke=s;renderTeSTabs();renderTeGrid();}
function renderTeGrid(){
  const a=S.athletes.find(x=>x.id===editTimesId);
  const evs=EVENTS.filter(e=>gStroke(e)===teStroke);
  document.getElementById('teGrid').innerHTML=evs.map(ev=>`<div class="tecell"><div class="telbl">${ev}</div><input class="tein" type="text" data-ev="${ev}" value="${a.times[ev]||''}" placeholder="e.g. 1:23.45"></div>`).join('');
}
function saveTimes(){
  const a=S.athletes.find(x=>x.id===editTimesId);if(!a)return;
  document.querySelectorAll('#teGrid .tein').forEach(i=>{const v=i.value.trim();if(v)a.times[i.dataset.ev]=v;else delete a.times[i.dataset.ev];});
  save();closeModal('mtimes');if(curPage==='profile')showProfile(editTimesId);renderRoster();
}

// ── NAVIGATION ───────────────────────────────────────────────
function showPage(p){
  document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));
  // Use data-page attribute for reliable tab highlighting
  document.querySelectorAll('.ntab').forEach(x=>x.classList.remove('active'));
  const pageEl=document.getElementById('page-'+p);
  if(pageEl) pageEl.classList.add('active');
  curPage=p;
  // Highlight the matching nav tab by data-page
  document.querySelectorAll('.ntab[data-page]').forEach(t=>{
    if(t.dataset.page===p) t.classList.add('active');
  });
  document.getElementById('fabBtn').style.display=(p==='roster'||p==='profile')?'flex':'none';
  if(p==='roster')renderRoster();
  else if(p==='chart')renderChart();
  else if(p==='overview')renderOverview();
  else if(p==='standards')renderStdsTable();
  else if(p==='settings'){
    renderSettStds();
    document.getElementById('stn').value=S.teamName;
    // Sync theme button labels
    const isLight=S.theme==='light';
    const sb=document.getElementById('themeSettingBtn');
    if(sb) sb.textContent=isLight?'Switch to Dark Mode':'Switch to Light Mode';
    const sn=document.getElementById('themeSettingNote');
    if(sn) sn.textContent=isLight?'Currently: Light':'Currently: Dark';
    const tb=document.getElementById('themeToggleBtn');
    if(tb) tb.textContent=isLight?'Dark Mode':'Light Mode';
  }
  else if(p==='analytics'&&typeof renderAnalyticsPage==='function')renderAnalyticsPage();
}

function setGF(f){gFilt=f;document.getElementById('gA').className='gbtn'+(f==='all'?' aa':'');document.getElementById('gM').className='gbtn'+(f==='male'?' am':'');document.getElementById('gF').className='gbtn'+(f==='female'?' af':'');renderRoster();}
function toggleCG(){chartG=chartG==='female'?'male':'female';renderChart();}
function toggleSVG(){stdVG=stdVG==='female'?'male':'female';renderStdsTable();}
function toggleLbG(){const s=['all','male','female'];lbG=s[(s.indexOf(lbG)+1)%3];document.getElementById('lbgBtn').textContent=lbG==='all'?'All':lbG==='male'?'♂ Men':'♀ Women';renderLB();}

// ── TEAM BRANDING ────────────────────────────────────────────
function updateTeamName(v){if(!v)return;S.teamName=v;document.getElementById('tns').textContent=v;document.getElementById('stn').value=v;document.getElementById('logoTN').value=v;save();}

function handleLogo(ev){
  const file=ev.target.files[0];if(!file)return;
  const r=new FileReader();
  r.onload=e=>{S.teamLogo=e.target.result;applyLogo();save();};
  r.readAsDataURL(file);
}
function applyLogo(){
  if(!S.teamLogo)return;
  const ltxt=document.getElementById('ltxt');const limg=document.getElementById('limg');
  const lptxt=document.getElementById('lptxt');const lpimg=document.getElementById('lpimg');
  if(ltxt)ltxt.style.display='none';
  if(limg){limg.src=S.teamLogo;limg.style.display='block';}
  if(lptxt)lptxt.style.display='none';
  if(lpimg){lpimg.src=S.teamLogo;lpimg.style.display='block';}
}

